   224→   * @returns Promise that resolves when all items are written
   225→   */
   226→  async setItemsBatch(items: Record<string, string>): Promise<void> {
   227→    await this.init();
   228→
   229→    return new Promise((resolve, reject) => {
   230→      const transaction = this.connection.db!.transaction(STORE_NAME, 'readwrite');
   231→      const store = transaction.objectStore(STORE_NAME);
   232→
   233→      // Write all items in a single transaction
   234→      Object.entries(items).forEach(([key, value]) => {
   235→        store.put(value, key);
   236→      });
   237→
   238→      transaction.oncomplete = () => {
   239→        log.debug('Batch wrote items to IndexedDB', { count: Object.keys(items).length });
   240→        resolve();
   241→      };
   242→
   243→      transaction.onerror = () => {
   244→        log.error('Failed to batch write items', { error: transaction.error });
   245→        reject(transaction.error);
   246→      };
   247→    });
   248→  }
