   250→  /**
   251→   * Batch read multiple items in a single transaction
   252→   * @param keys - Array of keys to read
   253→   * @returns Promise with object containing key-value pairs (missing keys are omitted)
   254→   */
   255→  async getItemsBatch(keys: string[]): Promise<Record<string, string>> {
   256→    await this.init();
   257→
   258→    return new Promise((resolve, reject) => {
   259→      const transaction = this.connection.db!.transaction(STORE_NAME, 'readonly');
   260→      const store = transaction.objectStore(STORE_NAME);
   261→      const results: Record<string, string> = {};
   262→      let pending = keys.length;
   263→
   264→      if (pending === 0) {
   265→        resolve({});
   266→        return;
   267→      }
   268→
   269→      keys.forEach((key) => {
   270→        const request = store.get(key);
   271→        request.onsuccess = () => {
   272→          if (request.result !== undefined) {
   273→            results[key] = request.result;
   274→          }
   275→          if (--pending === 0) {
   276→            log.debug('Batch read items from IndexedDB', { found: Object.keys(results).length, requested: keys.length });
   277→            resolve(results);
   278→          }
   279→        };
   280→      });
   281→
   282→      transaction.onerror = () => {
   283→        log.error('Failed to batch read items', { error: transaction.error });
   284→        reject(transaction.error);
   285→      };
   286→    });
   287→  }
