   289→  /**
   290→   * Get storage quota information
   291→   */
   292→  async getQuota(): Promise<{
   293→    usage: number;
   294→    quota: number;
   295→    percentUsed: number;
   296→    available: number;
   297→    usageFormatted: string;
   298→    quotaFormatted: string;
   299→    availableFormatted: string;
   300→  }> {
   301→    if ('storage' in navigator && 'estimate' in navigator.storage) {
   302→      const estimate = await navigator.storage.estimate();
   303→      const usage = estimate.usage || 0;
   304→      const quota = estimate.quota || 0;
   305→      const percentUsed = quota > 0 ? (usage / quota) * 100 : 0;
   306→      const available = quota - usage;
   307→
   308→      return {
   309→        usage,
   310→        quota,
   311→        percentUsed,
   312→        available,
   313→        usageFormatted: this.formatBytes(usage),
   314→        quotaFormatted: this.formatBytes(quota),
   315→        availableFormatted: this.formatBytes(available),
   316→      };
   317→    }
   318→
   319→    // Fallback for browsers without Storage API
   320→    return {
   321→      usage: 0,
   322→      quota: 0,
   323→      percentUsed: 0,
   324→      available: 0,
   325→      usageFormatted: '0 Bytes',
   326→      quotaFormatted: '0 Bytes',
   327→      availableFormatted: '0 Bytes',
   328→    };
   329→  }
   330→
   331→  /**
   332→   * Format bytes to human-readable string
   333→   */
   334→  formatBytes(bytes: number): string {
   335→    if (bytes === 0) return '0 Bytes';
   336→    const k = 1024;
   337→    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
   338→    const i = Math.floor(Math.log(bytes) / Math.log(k));
   339→    return `${Math.round((bytes / Math.pow(k, i)) * 100) / 100} ${sizes[i]}`;
   340→  }
   341→
   342→  /**
   343→   * Check if storage is getting full (>80%)
   344→   */
   345→  async isStorageNearlyFull(): Promise<boolean> {
   346→    const quota = await this.getQuota();
   347→    return quota.percentUsed > 80;
   348→  }
   349→
   350→  /**
   351→   * Check if IndexedDB is supported
   352→   */
   353→  isSupported(): boolean {
   354→    return typeof indexedDB !== 'undefined';
   355→  }
   356→
   357→  /**
   358→   * Store an object (structured clone) in IndexedDB
   359→   * Useful for storing FileSystemDirectoryHandle and other complex objects
   360→   */
   361→  async setObject(key: string, value: any): Promise<void> {
   362→    await this.init();
   363→
   364→    return new Promise((resolve, reject) => {
   365→      if (!this.connection.db) {
   366→        reject(new Error('IndexedDB not initialized'));
   367→        return;
   368→      }
   369→
   370→      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
   371→      const store = transaction.objectStore(STORE_NAME);
   372→      const request = store.put(value, key);
   373→
   374→      request.onsuccess = () => {
   375→        resolve();
   376→      };
   377→
   378→      request.onerror = () => {
   379→        log.error('Failed to set object in IndexedDB', { key, error: request.error });
   380→        reject(request.error);
   381→      };
   382→    });
   383→  }
   384→
   385→  /**
   386→   * Retrieve an object from IndexedDB
   387→   */
   388→  async getObject<T = any>(key: string): Promise<T | null> {
   389→    await this.init();
   390→
   391→    return new Promise((resolve, reject) => {
   392→      if (!this.connection.db) {
   393→        reject(new Error('IndexedDB not initialized'));
   394→        return;
   395→      }
   396→
   397→      const transaction = this.connection.db.transaction(STORE_NAME, 'readonly');
   398→      const store = transaction.objectStore(STORE_NAME);
   399→      const request = store.get(key);
   400→
   401→      request.onsuccess = () => {
   402→        resolve(request.result ?? null);
   403→      };
   404→
   405→      request.onerror = () => {
   406→        log.error('Failed to get object from IndexedDB', { key, error: request.error });
   407→        reject(request.error);
   408→      };
   409→    });
   410→  }
   411→
   412→  /**
   413→   * Compress and store an image blob
   414→   * - Resizes to max 1920x1080
   415→   * - Compresses to 85% JPEG quality
   416→   * - Returns image ID (key)
   417→   */
   418→  async storeImage(noteId: string, imageFile: File | Blob): Promise<string> {
   419→    // Check quota before upload
   420→    const quota = await this.getQuota();
   421→    const MIN_AVAILABLE = 10 * 1024 * 1024; // 10MB minimum
   422→
   423→    if (quota.available < MIN_AVAILABLE) {
   424→      throw new Error(`Insufficient storage: ${quota.availableFormatted} remaining. Need at least 10MB.`);
   425→    }
   426→
   427→    // Compress image
   428→    const compressedBlob = await this.compressImage(imageFile);
   429→
   430→    // Generate unique image ID
   431→    const imageId = `image_${noteId}_${Date.now()}_${Math.random().toString(36).substring(7)}`;
   432→
   433→    // Store blob using setObject (IndexedDB supports blobs natively)
   434→    await this.setObject(imageId, compressedBlob);
   435→
   436→    log.debug('Stored image', { imageId, compressedSize: this.formatBytes(compressedBlob.size), originalSize: this.formatBytes(imageFile.size) });
   437→
   438→    return imageId;
   439→  }
   440→
   441→  /**
   442→   * Retrieve an image blob by ID
   443→   */
   444→  async getImage(imageId: string): Promise<Blob | null> {
   445→    const blob = await this.getObject<Blob>(imageId);
   446→    return blob;
   447→  }
   448→
   449→  /**
   450→   * Delete an image blob by ID
   451→   */
   452→  async deleteImage(imageId: string): Promise<void> {
   453→    await this.removeItem(imageId);
   454→    log.debug('Deleted image', { imageId });
   455→  }
   456→
   457→  /**
   458→   * Delete all images associated with a note
   459→   * @param noteId - Note ID to delete images for
   460→   */
   461→  async deleteNoteImages(noteId: string): Promise<void> {
   462→    const keys = await this.getAllKeys();
   463→    const imageKeys = keys.filter(key => key.startsWith(`image_${noteId}_`));
   464→
   465→    for (const imageKey of imageKeys) {
   466→      await this.removeItem(imageKey);
   467→    }
   468→
   469→    if (imageKeys.length > 0) {
   470→      log.debug('Deleted note images', { noteId, count: imageKeys.length });
   471→    }
   472→  }
   473→
   474→  /**
   475→   * Compress image to max 1920x1080 at 85% quality
   476→   * Returns compressed JPEG blob
   477→   */
   478→  private async compressImage(file: File | Blob): Promise<Blob> {
   479→    return new Promise((resolve, reject) => {
   480→      const img = new Image();
   481→      const objectUrl = URL.createObjectURL(file);
   482→
   483→      img.onload = () => {
   484→        // Calculate target dimensions (max 1920x1080, maintain aspect ratio)
   485→        const MAX_WIDTH = 1920;
   486→        const MAX_HEIGHT = 1080;
   487→        let width = img.width;
   488→        let height = img.height;
   489→
   490→        // Scale down if needed
   491→        if (width > MAX_WIDTH || height > MAX_HEIGHT) {
   492→          const widthRatio = MAX_WIDTH / width;
   493→          const heightRatio = MAX_HEIGHT / height;
   494→          const ratio = Math.min(widthRatio, heightRatio);
   495→
   496→          width = Math.round(width * ratio);
   497→          height = Math.round(height * ratio);
   498→        }
   499→
   500→        // Create canvas for compression
   501→        const canvas = document.createElement('canvas');
   502→        canvas.width = width;
   503→        canvas.height = height;
   504→
   505→        const ctx = canvas.getContext('2d');
   506→        if (!ctx) {
   507→          URL.revokeObjectURL(objectUrl);
   508→          reject(new Error('Failed to get canvas context'));
   509→          return;
   510→        }
   511→
   512→        // Draw image to canvas
   513→        ctx.drawImage(img, 0, 0, width, height);
   514→
   515→        // Convert to blob with 85% quality
   516→        canvas.toBlob(
   517→          (blob) => {
   518→            URL.revokeObjectURL(objectUrl);
   519→
   520→            if (!blob) {
   521→              reject(new Error('Failed to compress image'));
   522→              return;
   523→            }
   524→
   525→            resolve(blob);
   526→          },
   527→          'image/jpeg',
   528→          0.85 // 85% quality
   529→        );
   530→      };
   531→
   532→      img.onerror = () => {
   533→        URL.revokeObjectURL(objectUrl);
   534→        reject(new Error('Failed to load image'));
   535→      };
   536→
   537→      img.src = objectUrl;
   538→    });
   539→  }
   540→}
