   907→      convertToWikiLink: (noteId: string, position: number, targetTitle: string) => {
   908→        const state = get();
   909→        const note = state.notes[noteId];
   910→        if (!note) {
   911→          log.warn('Note not found for converting to wiki link', { noteId });
   912→          return;
   913→        }
   914→
   915→        const content = note.contentText;
   916→
   917→        // Find the exact text match at the position
   918→        const titleLength = targetTitle.length;
   919→        const endPosition = position + titleLength;
   920→
   921→        // Extract the text at the position to verify it matches
   922→        const textAtPosition = content.substring(position, endPosition);
   923→
   924→        // Case-insensitive match check
   925→        if (textAtPosition.toLowerCase() !== targetTitle.toLowerCase()) {
   926→          log.warn('Text at position does not match target title', {
   927→            noteId,
   928→            position,
   929→            targetTitle,
   930→            textAtPosition,
   931→          });
   932→          return;
   933→        }
   934→
   935→        // Build the new content with wiki link
   936→        const before = content.substring(0, position);
   937→        const after = content.substring(endPosition);
   938→        const wikiLink = `[[${textAtPosition}]]`; // Preserve original case
   939→        const newContentText = before + wikiLink + after;
   940→
   941→        // Update the note using the updateNote action to ensure proper handling
   942→        get().updateNote(noteId, { contentText: newContentText });
   943→
   944→        log.debug('Converted text to wiki link', {
   945→          noteId,
   946→          position,
   947→          targetTitle,
   948→          originalText: textAtPosition,
   949→        });
   950→      },
