  1028→        log.info('Auto-created daily note', { date: newNote.title, id: newNote.id });
  1029→        return newNote;
  1030→      },
  1031→
  1032→      // ==================== P2: BLOCK-LEVEL LINKS & HOVER PREVIEW ====================
  1033→
  1034→      getBlockContent: (noteId: string, blockId: string) => {
  1035→        const note = get().notes[noteId];
  1036→        if (!note) return null;
  1037→
  1038→        const blockInfo = findBlockInContent(note.contentText, blockId);
  1039→        return blockInfo ? blockInfo.content : null;
