  1069→                  note.updatedAt = new Date(note.updatedAt);
  1070→                }
  1071→              });
  1072→            } else {
  1073→              log.warn('Corrupted notes data detected, resetting to empty');
  1074→              state.notes = {};
  1075→            }
  1076→          } catch (err) {
  1077→            log.error('Error during notes store rehydration', { error: err });
  1078→            // Reset to safe defaults
