   527→      replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => {
   528→        const state = get();
   529→
   530→        // Save undo entry BEFORE making changes
   531→        get().addToUndoHistory({
   532→          action: 'replaceAllColumns',
   533→          description: `Applied template`,
   534→          previousState: {
   535→            columns: state.columns,
   536→            tasks: state.tasks,
   537→          },
   538→        });
   539→
   540→        // Generate new columns with fresh IDs and correct order
   541→        const columns: KanbanColumn[] = newColumns.map((col, index) => ({
   542→          ...col,
   543→          id: `col-${Date.now()}-${index}`,
   544→          order: index,
   545→        }));
   546→
   547→        if (columns.length === 0) {
   548→          log.error('No columns provided for replacement');
   549→          return;
   550→        }
   551→
   552→        // Smart mapping: Try to preserve task positions based on column titles
   553→        const tasks = state.tasks.map(task => {
   554→          const oldColumn = state.columns.find(c => c.id === task.status);
   555→          if (!oldColumn) {
   556→            // Task has invalid status, move to first column
   557→            return { ...task, status: columns[0].id as TaskStatus };
   558→          }
   559→
   560→          // Try exact match first (case-insensitive)
   561→          let newColumn = columns.find(c =>
   562→            c.title.toLowerCase() === oldColumn.title.toLowerCase()
   563→          );
   564→
   565→          // If no exact match, try partial match (contains)
   566→          if (!newColumn) {
   567→            newColumn = columns.find(c =>
   568→              c.title.toLowerCase().includes(oldColumn.title.toLowerCase()) ||
   569→              oldColumn.title.toLowerCase().includes(c.title.toLowerCase())
   570→            );
   571→          }
   572→
   573→          // Fallback: first column
   574→          if (!newColumn) {
   575→            newColumn = columns[0];
   576→          }
   577→
   578→          return { ...task, status: newColumn.id as TaskStatus };
   579→        });
   580→
   581→        set({ columns, tasks });
