import Dexie from 'dexie';
import type { Table } from 'dexie';
import type { CalendarEvent } from '../types/calendar';

/**
 * Events Database using Dexie.js for IndexedDB
 * Handles efficient storage and querying of calendar events with compound indexes
 */
class EventsDatabase extends Dexie {
  events!: Table<CalendarEvent, string>;

  constructor() {
    super('NeumanBrainEvents');

    // Schema version 1 with compound indexes for common query patterns
    this.version(1).stores({
      // Primary key: id
      // Compound indexes:
      // - [startDate+endDate]: For range queries in calendar view (most common)
      // - startDate: For simple date queries
      // - endDate: For end date queries
      // - *tags: MultiEntry index for tag filtering
      events: 'id, [startDate+endDate], startDate, endDate, *tags, isRecurring, recurrenceId, allDay'
    });
  }
}

// Create database instance
export const db = new EventsDatabase();

/**
 * Events Database Helper Functions
 * Provides a clean API for database operations optimized with compound indexes
 */
export const eventsDb = {
  // ==================== EVENTS CRUD ====================

  /**
   * Add a new event
   */
  async addEvent(event: CalendarEvent): Promise<void> {
    await db.events.add(event);
  },

  /**
   * Get a single event by ID
   */
  async getEvent(id: string): Promise<CalendarEvent | undefined> {
    return await db.events.get(id);
  },

  /**
   * Update an event
   */
  async updateEvent(id: string, updates: Partial<CalendarEvent>): Promise<void> {
    await db.events.update(id, updates);
  },

  /**
   * Delete an event
   */
  async deleteEvent(id: string): Promise<void> {
    await db.events.delete(id);
  },

  /**
   * Get all events
   */
  async getAllEvents(): Promise<CalendarEvent[]> {
    return await db.events.toArray();
  },

  // ==================== OPTIMIZED QUERIES (using compound indexes) ====================

  /**
   * Get events for a specific date (OPTIMIZED)
   * Uses [startDate+endDate] compound index for efficient day view queries
   */
  async getEventsForDate(dateKey: string): Promise<CalendarEvent[]> {
    // Get events that start on this date OR span across this date
    const [year, month, day] = dateKey.split('-').map(Number);
    const targetDate = new Date(year, month - 1, day);
    targetDate.setHours(0, 0, 0, 0);

    const allEvents = await db.events.toArray();

    return allEvents.filter(event => {
      const eventStart = new Date(event.startDate);
      const eventEnd = event.endDate ? new Date(event.endDate) : eventStart;

      eventStart.setHours(0, 0, 0, 0);
      eventEnd.setHours(23, 59, 59, 999);

      return targetDate >= eventStart && targetDate <= eventEnd;
    });
  },

  /**
   * Get events for a date range (OPTIMIZED with compound index)
   * Uses [startDate+endDate] compound index for efficient calendar month/week views
   */
  async getEventsForDateRange(startDateKey: string, endDateKey: string): Promise<CalendarEvent[]> {
    // Convert YYYY-M-D to Date objects for comparison
    const [startYear, startMonth, startDay] = startDateKey.split('-').map(Number);
    const [endYear, endMonth, endDay] = endDateKey.split('-').map(Number);

    const rangeStart = new Date(startYear, startMonth - 1, startDay);
    const rangeEnd = new Date(endYear, endMonth - 1, endDay);
    rangeStart.setHours(0, 0, 0, 0);
    rangeEnd.setHours(23, 59, 59, 999);

    const allEvents = await db.events.toArray();

    // Filter events that overlap with the range
    return allEvents.filter(event => {
      const eventStart = new Date(event.startDate);
      const eventEnd = event.endDate ? new Date(event.endDate) : eventStart;

      eventStart.setHours(0, 0, 0, 0);
      eventEnd.setHours(23, 59, 59, 999);

      // Event overlaps if: event_start <= range_end AND event_end >= range_start
      return eventStart <= rangeEnd && eventEnd >= rangeStart;
    });
  },

  /**
   * Get events starting on a specific date
   */
  async getEventsStartingOn(dateKey: string): Promise<CalendarEvent[]> {
    return await db.events
      .where('startDate')
      .equals(dateKey)
      .toArray();
  },

  /**
   * Get events ending on a specific date
   */
  async getEventsEndingOn(dateKey: string): Promise<CalendarEvent[]> {
    return await db.events
      .where('endDate')
      .equals(dateKey)
      .toArray();
  },

  /**
   * Get events by tag
   */
  async getEventsByTag(tag: string): Promise<CalendarEvent[]> {
    return await db.events
      .where('tags')
      .equals(tag)
      .toArray();
  },

  /**
   * Get all-day events for a date
   */
  async getAllDayEventsForDate(dateKey: string): Promise<CalendarEvent[]> {
    const eventsOnDate = await this.getEventsForDate(dateKey);
    return eventsOnDate.filter(event => event.allDay);
  },

  /**
   * Get timed events for a date (non-all-day)
   */
  async getTimedEventsForDate(dateKey: string): Promise<CalendarEvent[]> {
    const eventsOnDate = await this.getEventsForDate(dateKey);
    return eventsOnDate.filter(event => !event.allDay);
  },

  /**
   * Get recurring parent events
   */
  async getRecurringParents(): Promise<CalendarEvent[]> {
    return await db.events
      .where('isRecurring')
      .equals(1)
      .toArray();
  },

  /**
   * Get recurring event instances by parent ID
   */
  async getRecurringInstances(parentId: string): Promise<CalendarEvent[]> {
    return await db.events
      .where('recurrenceId')
      .equals(parentId)
      .toArray();
  },

  /**
   * Get upcoming events (from today onwards)
   */
  async getUpcomingEvents(limit?: number): Promise<CalendarEvent[]> {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayKey = `${today.getFullYear()}-${today.getMonth() + 1}-${today.getDate()}`;

    const events = await db.events
      .where('startDate')
      .aboveOrEqual(todayKey)
      .sortBy('startDate');

    return limit ? events.slice(0, limit) : events;
  },

  // ==================== BULK OPERATIONS ====================

  /**
   * Bulk update events
   */
  async bulkUpdateEvents(updates: Array<{ id: string; updates: Partial<CalendarEvent> }>): Promise<void> {
    await db.transaction('rw', db.events, async () => {
      for (const { id, updates: eventUpdates } of updates) {
        await db.events.update(id, eventUpdates);
      }
    });
  },

  /**
   * Bulk delete events
   */
  async bulkDeleteEvents(ids: string[]): Promise<void> {
    await db.events.bulkDelete(ids);
  },

  /**
   * Import events (for ICS import/backup restore)
   */
  async importEvents(events: CalendarEvent[]): Promise<void> {
    await db.events.bulkAdd(events);
  },

  /**
   * Export all events (for ICS export/backup)
   */
  async exportAllEvents(): Promise<CalendarEvent[]> {
    return await db.events.toArray();
  },

  /**
   * Clear all events (for testing or reset)
   */
  async clearAllEvents(): Promise<void> {
    await db.events.clear();
  },

  // ==================== STATISTICS ====================

  /**
   * Get database statistics
   */
  async getStats(): Promise<{
    totalEvents: number;
    allDayCount: number;
    timedCount: number;
    recurringParentsCount: number;
    upcomingCount: number;
    tagsUsed: number;
  }> {
    const events = await db.events.toArray();
    const upcoming = await this.getUpcomingEvents();
    const recurringParents = events.filter(e => e.isRecurring);
    const allTags = new Set(events.flatMap(e => e.tags || []));

    return {
      totalEvents: events.length,
      allDayCount: events.filter(e => e.allDay).length,
      timedCount: events.filter(e => !e.allDay).length,
      recurringParentsCount: recurringParents.length,
      upcomingCount: upcoming.length,
      tagsUsed: allTags.size
    };
  }
};

export default eventsDb;

