import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import { visualizer } from 'rollup-plugin-visualizer'

// https://vite.dev/config/
export default defineConfig({
  plugins: [
    react(),
    visualizer({
      open: false, // Don't auto-open browser (manual check via stats.html)
      filename: 'dist/stats.html',
      gzipSize: true,
      brotliSize: true,
    })
  ],

  // CSS configuration with PostCSS
  css: {
    postcss: './config/postcss.config.js',
  },

  // Base public path - use '/' for root domain deployment
  base: '/',

  // Build optimizations
  build: {
    // Output directory
    outDir: 'dist',

    // Generate sourcemaps for production debugging (optional)
    sourcemap: false,

    // Chunk size warnings
    chunkSizeWarningLimit: 1000,

    // Rollup options with manual chunking for vendors, UI, and stores
    rollupOptions: {
      output: {
        manualChunks: {
          // Vendor chunk: React core and router
          vendor: ['react', 'react-dom', 'react-router-dom'],

          // UI chunk: Component libraries
          ui: [
            'framer-motion',
            'lucide-react',
            '@dnd-kit/core',
            '@dnd-kit/sortable',
            '@dnd-kit/utilities',
            'recharts',
            'd3',
            'konva',
            'react-konva'
          ],

          // Store chunk: State management
          store: ['zustand', 'dexie'],

          // Editor chunk: Lexical rich text editor
          editor: [
            'lexical',
            '@lexical/react',
